import React, { useState, useEffect } from 'react';
import { Link, useStaticQuery, graphql } from 'gatsby';
import SearchOverlay from './SearchOverlay';

interface SiteMetadata {
  site: {
    siteMetadata: {
      title: string;
      navigation: Array<{
        name: string;
        path: string;
      }>;
      socialLinks: {
        github: string;
        linkedin: string;
      };
    };
  };
}

const Header: React.FC = () => {
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Lock body scroll when mobile menu or search is open
  useEffect(() => {
    if (isMobileMenuOpen || isSearchOpen) {
      document.body.style.overflow = 'hidden';
      // iOS Safari fix: prevent rubber-band scrolling
      document.body.style.position = 'fixed';
      document.body.style.width = '100%';
    } else {
      document.body.style.overflow = '';
      document.body.style.position = '';
      document.body.style.width = '';
    }
    
    return () => {
      document.body.style.overflow = '';
      document.body.style.position = '';
      document.body.style.width = '';
    };
  }, [isMobileMenuOpen, isSearchOpen]);

  useEffect(() => {
    const savedTheme = localStorage.getItem('theme');
    const theme = savedTheme === 'light' ? 'light' : 'dark';
    setIsDarkMode(theme === 'dark');

    if (theme === 'dark') {
      document.documentElement.classList.add('hm-dark');
    } else {
      document.documentElement.classList.remove('hm-dark');
    }
    
    // Set user property for theme preference
    if (typeof window !== 'undefined' && window.gtag) {
      window.gtag('set', 'user_properties', {
        theme_preference: theme,
      });
    }
  }, []);

  const toggleDarkMode = () => {
    const newMode = !isDarkMode;
    setIsDarkMode(newMode);
    
    const theme = newMode ? 'dark' : 'light';
    
    if (newMode) {
      document.documentElement.classList.add('hm-dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('hm-dark');
      localStorage.setItem('theme', 'light');
    }
    
    // Track theme toggle event
    if (typeof window !== 'undefined' && window.gtag) {
      window.gtag('event', 'theme_toggle', {
        theme_mode: theme,
        event_category: 'engagement',
        event_label: `Theme changed to ${theme}`,
      });
    }
  };

  const data = useStaticQuery<SiteMetadata>(graphql`
    query HeaderQuery {
      site {
        siteMetadata {
          title
          navigation {
            name
            path
          }
          socialLinks {
            github
            linkedin
          }
        }
      }
    }
  `);

  const { title, navigation, socialLinks } = data.site.siteMetadata;

  return (
    <>
      <header id="masthead" className="site-header">
      <div className="hm-header-inner-wrapper">
        <div className="hm-header-inner hm-container">
          
          {/* Site Branding */}
          <div className="site-branding-container">
            <div className="site-branding">
              <h1 className="site-title">
                <Link to="/" rel="home">{title}</Link>
              </h1>
            </div>
          </div>

          {/* Desktop Navigation */}
          <nav id="site-navigation" className="main-navigation hm-menu desktop-only">
            <ul id="primary-menu" className="menu">
              {navigation.map((item) => (
                <li key={item.path} className="menu-item">
                  <Link to={item.path}>{item.name}</Link>
                </li>
              ))}
            </ul>
          </nav>

          {/* Header Gadgets (Social, Theme Toggle, Search) */}
          <div className="hm-header-gadgets">
            
            {/* Social Menu */}
            <nav className="hm-social-menu hm-social-nav" aria-label="Social links">
              <ul className="hm-social-menu hm-social-icons">
                <li className="menu-item">
                  <a href={socialLinks.github} target="_blank" rel="noopener noreferrer">
                    <span className="screen-reader-text">GitHub</span>
                    <svg aria-hidden="true" xmlns="http://www.w3.org/2000/svg" width="1em" height="1em" viewBox="0 0 496 512" className="hm-svg-icon hm-github">
                      <path d="M165.9 397.4c0 2-2.3 3.6-5.2 3.6-3.3.3-5.6-1.3-5.6-3.6 0-2 2.3-3.6 5.2-3.6 3-.3 5.6 1.3 5.6 3.6zm-31.1-4.5c-.7 2 1.3 4.3 4.3 4.9 2.6 1 5.6 0 6.2-2s-1.3-4.3-4.3-5.2c-2.6-.7-5.5.3-6.2 2.3zm44.2-1.7c-2.9.7-4.9 2.6-4.6 4.9.3 2 2.9 3.3 5.9 2.6 2.9-.7 4.9-2.6 4.6-4.6-.3-1.9-3-3.2-5.9-2.9zM244.8 8C106.1 8 0 113.3 0 252c0 110.9 69.8 205.8 169.5 239.2 12.8 2.3 17.3-5.6 17.3-12.1 0-6.2-.3-40.4-.3-61.4 0 0-70 15-84.7-29.8 0 0-11.4-29.1-27.8-36.6 0 0-22.9-15.7 1.6-15.4 0 0 24.9 2 38.6 25.8 21.9 38.6 58.6 27.5 72.9 20.9 2.3-16 8.8-27.1 16-33.7-55.9-6.2-112.3-14.3-112.3-110.5 0-27.5 7.6-41.3 23.6-58.9-2.6-6.5-11.1-33.3 2.6-67.9 20.9-6.5 69 27 69 27 20-5.6 41.5-8.5 62.8-8.5s42.8 2.9 62.8 8.5c0 0 48.1-33.6 69-27 13.7 34.7 5.2 61.4 2.6 67.9 16 17.7 25.8 31.5 25.8 58.9 0 96.5-58.9 104.2-114.8 110.5 9.2 7.9 17 22.9 17 46.4 0 33.7-.3 75.4-.3 83.6 0 6.5 4.6 14.4 17.3 12.1C428.2 457.8 496 362.9 496 252 496 113.3 383.5 8 244.8 8zM97.2 352.9c-1.3 1-1 3.3.7 5.2 1.6 1.6 3.9 2.3 5.2 1 1.3-1 1-3.3-.7-5.2-1.6-1.6-3.9-2.3-5.2-1zm-10.8-8.1c-.7 1.3.3 2.9 2.3 3.9 1.6 1 3.6.7 4.3-.7.7-1.3-.3-2.9-2.3-3.9-2-.6-3.6-.3-4.3.7zm32.4 35.6c-1.6 1.3-1 4.3 1.3 6.2 2.3 2.3 5.2 2.6 6.5 1 1.3-1.3.7-4.3-1.3-6.2-2.2-2.3-5.2-2.6-6.5-1zm-11.4-14.7c-1.6 1-1.6 3.6 0 5.9 1.6 2.3 4.3 3.3 5.6 2.3 1.6-1.3 1.6-3.9 0-6.2-1.4-2.3-4-3.3-5.6-2z" />
                    </svg>
                  </a>
                </li>
                <li className="menu-item">
                  <a href={socialLinks.linkedin} target="_blank" rel="noopener noreferrer">
                    <span className="screen-reader-text">LinkedIn</span>
                    <svg aria-hidden="true" xmlns="http://www.w3.org/2000/svg" width="1em" height="1em" viewBox="0 0 448 512" className="hm-svg-icon hm-linkedin">
                      <path d="M416 32H31.9C14.3 32 0 46.5 0 64.3v383.4C0 465.5 14.3 480 31.9 480H416c17.6 0 32-14.5 32-32.3V64.3c0-17.8-14.4-32.3-32-32.3zM135.4 416H69V202.2h66.5V416zm-33.2-243c-21.3 0-38.5-17.3-38.5-38.5S80.9 96 102.2 96c21.2 0 38.5 17.3 38.5 38.5 0 21.3-17.2 38.5-38.5 38.5zm282.1 243h-66.4V312c0-24.8-.5-56.7-34.5-56.7-34.6 0-39.9 27-39.9 54.9V416h-66.4V202.2h63.7v29.2h.9c8.9-16.8 30.6-34.5 62.9-34.5 67.2 0 79.7 44.3 79.7 101.9V416z" />
                    </svg>
                  </a>
                </li>
              </ul>
            </nav>

            {/* Dark Mode Toggle */}
            <div className="hm-light-dark-switch">
              <button 
                className="hm-light-dark-toggle"
                aria-label="Toggle dark mode"
                onClick={toggleDarkMode}
              >
                <span className="screen-reader-text">Toggle dark mode</span>
                <span className="hm-light-icon">{isDarkMode ? '🌙' : '☀️'}</span>
              </button>
            </div>

            {/* Search Toggle */}
            <div className="hm-search-toggle-wrapper">
              <button 
                className="hm-search-toggle"
                aria-label="Open search"
                onClick={() => setIsSearchOpen(true)}
              >
                <span className="screen-reader-text">Open Search</span>
                <span className="hm-search-icon">🔍</span>
              </button>
            </div>

            {/* Mobile Menu Toggle */}
            <button 
              className="hm-mobile-menu-toggle" 
              aria-label="Open mobile menu"
              onClick={() => setIsMobileMenuOpen(true)}
            >
              <span className="screen-reader-text">Main Menu</span>
              <span className="hm-menu-bars">☰</span>
            </button>
          </div>
        </div>
      </div>
    </header>
    
    <SearchOverlay 
      isOpen={isSearchOpen} 
      onClose={() => setIsSearchOpen(false)} 
    />
    
    {/* Mobile Navigation Menu */}
    {isMobileMenuOpen && (
      <div className="hm-mobile-menu-overlay" onClick={() => setIsMobileMenuOpen(false)}>
        <nav className="hm-mobile-navigation" onClick={(e) => e.stopPropagation()}>
          <div className="hm-mobile-menu-header">
            <span className="hm-mobile-menu-title">Menu</span>
            <button 
              className="hm-mobile-menu-close" 
              aria-label="Close mobile menu"
              onClick={() => setIsMobileMenuOpen(false)}
            >
              ✕
            </button>
          </div>
          <ul className="hm-mobile-menu-list">
            {navigation.map((item) => (
              <li key={item.path} className="hm-mobile-menu-item">
                <Link to={item.path} onClick={() => setIsMobileMenuOpen(false)}>
                  {item.name}
                </Link>
              </li>
            ))}
          </ul>
          <div className="hm-mobile-menu-social">
            <a href={socialLinks.github} target="_blank" rel="noopener noreferrer">GitHub</a>
            <a href={socialLinks.linkedin} target="_blank" rel="noopener noreferrer">LinkedIn</a>
          </div>
        </nav>
      </div>
    )}
  </>
  );
};

export default Header;

